import{_ as c,C as t,o as g,c as m,j as e,a as n,E as i,a3 as u}from"./chunks/framework.gsMzR_Kb.js";const y=JSON.parse('{"title":"太上老君说常清静经","description":"一部由大道落到清静工夫的短经。","frontmatter":{"title":"太上老君说常清静经","description":"一部由大道落到清静工夫的短经。","category":"guide","aliases":["清静经","常清静经","qingjing jing"],"source":["《太上老君说常清静经》"]},"headers":[],"relativePath":"daoism/starter-texts/qingjing-jing.md","filePath":"daoism/starter-texts/qingjing-jing.md","lastUpdated":1777132262000}'),b={name:"daoism/starter-texts/qingjing-jing.md"};function x(q,a,_,P,f,k){const r=t("DaoReadingPrelude"),o=t("DaoOriginalReading"),l=t("DaoLineGuide"),d=t("DaoTraditionAppendix"),s=t("DaoPinyinGlossary"),p=t("DaoParallelReading"),h=t("DaoKeywordCards");return g(),m("div",null,[a[0]||(a[0]=e("h1",{id:"太上老君说常清静经",tabindex:"-1"},[n("太上老君说常清静经 "),e("a",{class:"header-anchor",href:"#太上老君说常清静经","aria-label":'Permalink to "太上老君说常清静经"'},"​")],-1)),i(r,{title:"先看大道如何落到清静工夫",summary:"这部经先从大道说起，再一路收回到人的心如何遣欲、观照、复归清静。第一次读时，最适合先抓住“道体总说、清浊动静、人心为何不静、观照工夫、真静得道”这几层。",points:[{label:"先读",text:"先顺着正文读一遍，感受从大道落到人心的路径。"},{label:"再辨",text:"留意清 / 浊、动 / 静、心 / 欲如何层层转进。"},{label:"后看",text:"最后再回到“常应常静”与“实无所得”的收束处。"}],hint:"正文偏义理与工夫，附录偏传承与护持；第一次读时，可先把正文读清，再独立看后面的传承附录。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(o,{paragraphs:["老君曰：","大道无形，生育天地；大道无情，运行日月；大道无名，长养万物；吾不知其名，强名曰道。","夫道者：有清有浊，有动有静；天清地浊，天动地静；男清女浊，男动女静；降本流末，而生万物。清者浊之源，动者静之基；人能常清静，天地悉皆归。","夫人神好清，而心扰之；人心好静，而欲牵之。常能遣其欲，而心自静；澄其心，而神自清；自然六欲不生，三毒消灭。所以不能者，为心未澄，欲未遣也。能遣之者：内观其心，心无其心；外观其形，形无其形；远观其物，物无其物。三者既悟，唯见於空。","观空亦空，空无所空；所空既无，无无亦无；无无既无，湛然常寂。寂无所寂，欲岂能生？欲既不生，即是真静。真常应物，真常得性；常应常静，常清静矣。","如此清静，渐入真道；既入真道，名为得道；虽名得道，实无所得；为化众生，名为得道；能悟之者，可传圣道。"]}),i(l,{lines:[{text:"大道无形，生育天地；大道无情，运行日月；大道无名，长养万物；吾不知其名，强名曰道。",tone:"道体 · 先开门",guide:"这一段先不要只读成抽象玄理，它是在说大道虽然不执形名，却始终生育、运行、长养万物。"},{text:"夫道者：有清有浊，有动有静……人能常清静，天地悉皆归。",tone:"生成 · 清浊动静",guide:"清与浊、动与静不是切开的两端，而是在同一流行里互为根柢，所以最后才会收回到“人能常清静”。"},{text:"夫人神好清，而心扰之；人心好静，而欲牵之……三者既悟，唯见於空。",tone:"工夫 · 先遣其欲",guide:"这一段最适合从自身经验去读：不是人不想静，而是心会自扰、欲会牵引，所以修持先落在澄心遣欲与观照。"},{text:"观空亦空……常应常静，常清静矣。",tone:"真静 · 不离应物",guide:"“真静”不是逃开世界，而是在应物之中仍不失其根，所以后面才说“真常应物，常应常静”。"},{text:"如此清静，渐入真道……能悟之者，可传圣道。",tone:"得道 · 无所得",guide:"经文最后既说“渐入真道”，又马上补上“实无所得”，提醒人不要把修行又执成新的占有。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】传承附录",tabindex:"-1"},[n("【原典层】传承附录 "),e("a",{class:"header-anchor",href:"#【原典层】传承附录","aria-label":'Permalink to "【原典层】传承附录"'},"​")],-1)),i(d,{description:"附录部分偏向传承谱系、护持与信受传统，和正文的义理工夫不同，适合独立成卷来读。",image:"https://www.fridolph.top/static/dao/qingjingjing.png","image-alt":"太上老君说常清静经",entries:[{speaker:"葛翁",role:"传授谱系",text:"吾得真道，曾诵此经万遍。此经是天人所习，不传下士。吾昔受之于东华帝君，东华帝君受之于金阙帝君，金阙帝君受之于西王母。西王母皆口口相传，不记文字。吾今于世，书而录之。上士悟之，升为天官；中士修之，南宫列仙；下士得之，在世长年。游行三界，升入金门。",note:"这一段主要建立经典的传授来源与信受权威。"},{speaker:"左玄真人",role:"护持功能",text:"学道之士，持诵此经者，即得十天善神，拥护其身。然后玉符保神，金液炼形。形神俱妙，与道合真。",note:"强调持诵后的护持与形神兼修。"},{speaker:"正一真人",role:"感应劝信",text:"人家有此经，悟解之者，灾障不干，众圣护门。神升上界，朝拜高真。功满德就，相感帝君。诵持不退，身腾紫云。",note:"更偏向感应、护门与劝信语气。"}]}),a[3]||(a[3]=e("h2",{id:"【原典层】注音-生僻字",tabindex:"-1"},[n("【原典层】注音 / 生僻字 "),e("a",{class:"header-anchor",href:"#【原典层】注音-生僻字","aria-label":'Permalink to "【原典层】注音 / 生僻字"'},"​")],-1)),i(s,{description:"这部经字数不多，但几个关键字很容易成为理解路口。",items:[{char:"澄",pinyin:"chéng",tag:"工夫字",note:"澄心之澄，有沉静、澄明之意。"},{char:"湛",pinyin:"zhàn",tag:"关键字",note:"湛然常寂，偏向澄澈、深静而不昏滞。"},{char:"寂",pinyin:"jì",tag:"常见字",note:"这里的寂偏向静定，不是死寂。"},{char:"悉",pinyin:"xī",tag:"常见误读",note:"悉皆归，即都归于其位。"},{char:"於",pinyin:"yú",tag:"古字",note:"於空的“於”，同“于”。"}]}),a[4]||(a[4]=e("h2",{id:"【原典层】分段",tabindex:"-1"},[n("【原典层】分段 "),e("a",{class:"header-anchor",href:"#【原典层】分段","aria-label":'Permalink to "【原典层】分段"'},"​")],-1)),i(p,{sections:[{label:"道体总说",original:"大道无形……强名曰道。",reading:"大道无形，生育天地；大道无情，运行日月；大道无名，长养万物；吾不知其名，强名曰道。",translation:"大道不能被固定形名穷尽，却始终在生育天地、运行日月、长养万物。"},{label:"清浊动静",original:"夫道者……天地悉皆归。",reading:"夫道者：有清有浊，有动有静……清者浊之源，动者静之基；人能常清静，天地悉皆归。",translation:"清浊动静不是彼此切断，而是在同一流行里生成万物；人若能常清静，便更能与天地秩序重新相应。"},{label:"人心与欲",original:"夫人神好清……唯见於空。",reading:"夫人神好清，而心扰之；人心好静，而欲牵之……三者既悟，唯见於空。",translation:"人本来向往清静，只是常被心的自扰与欲的牵引带走，所以工夫要落在遣欲、澄心与观照上。"},{label:"真静与应物",original:"观空亦空……常清静矣。",reading:"观空亦空，空无所空……真常应物，真常得性；常应常静，常清静矣。",translation:"真正的清静不是躲开万物，而是在应物之中依然不失其根，不再被欲望完全牵着走。"},{label:"渐入真道",original:"如此清静……可传圣道。",reading:"如此清静，渐入真道；既入真道，名为得道；虽名得道，实无所得。",translation:"修持可以说是“渐入真道”，但经文马上又提醒：真正的得道并不是占有了什么。"}]}),a[5]||(a[5]=e("h2",{id:"【原典层】关键词",tabindex:"-1"},[n("【原典层】关键词 "),e("a",{class:"header-anchor",href:"#【原典层】关键词","aria-label":'Permalink to "【原典层】关键词"'},"​")],-1)),i(h,{items:[{term:"道",meaning:"根本之道，不以固定形名被穷尽。",context:"经文一开始先说明：道不可被一句话完全定义，却始终生育万物。"},{term:"清静",meaning:"清明、安定、澄定，不是僵住不动。",context:"全经最后都收回到“常应常静，常清静矣”的状态。"},{term:"心",meaning:"念头活动、意识流转、内在扰动之处。",context:"人之所以不静，往往先是心自扰。"},{term:"神",meaning:"精神、灵明、清明之性。",context:"经文说“人神好清”，指出人本来就向往清明。"},{term:"欲",meaning:"牵引、执取、不断向外抓取的力量。",context:"遣欲不是粗暴压制，而是不再一路被欲牵着走。"},{term:"空",meaning:"空其执，不是把一切抹成虚无。",context:"观空的重点在松开执著，而不是否定世界本身。"},{term:"真常",meaning:"真实而恒常，不是暂时出现的一阵清静感。",context:"真常应物，正说明真正的静并不离开现实万物。"},{term:"应物",meaning:"面对万物、回应万物而不失其根。",context:"这也是经文中最能把修持从“静坐状态”拉回日用的一句。"}]}),a[6]||(a[6]=u('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><blockquote><p>解读仅个人观点，仅供参考，若有疏漏还望海涵，并批评指出</p></blockquote><h3 id="象-这部经在说什么" tabindex="-1">象：这部经在说什么 <a class="header-anchor" href="#象-这部经在说什么" aria-label="Permalink to &quot;象：这部经在说什么&quot;">​</a></h3><p>《清静经》先从大道谈起，再落到清浊、动静如何生成万物，最后回到人心：为什么人静不下来，又如何慢慢归于清静。</p><p>它不是单纯讲宇宙，也不是只讲修心技巧，而是把两者连在一起：大道如何生育天地，人又如何让自己的心重新与大道相应。</p><h3 id="理-为什么这部经重要" tabindex="-1">理：为什么这部经重要 <a class="header-anchor" href="#理-为什么这部经重要" aria-label="Permalink to &quot;理：为什么这部经重要&quot;">​</a></h3><p>这部经篇幅很短，却把几个核心问题讲得很集中：</p><ul><li>道不可执形、执名</li><li>清浊动静并非绝对对立，而是共同生成万物</li><li>人本来趋向清静，只是常被心与欲牵走</li><li>工夫不在于逃开世界，而在于应物之中仍不失其静</li></ul><p>它很适合作为入门短经，因为它同时给出世界观、心性判断和工夫路径。</p><h3 id="用-今天怎么进入这部经" tabindex="-1">用：今天怎么进入这部经 <a class="header-anchor" href="#用-今天怎么进入这部经" aria-label="Permalink to &quot;用：今天怎么进入这部经&quot;">​</a></h3><p>今天读《清静经》，不必先把它读成神秘经文，而可以先把它看作一篇“心如何被扰，又如何复归清静”的短文。</p><p>可以从三个问题进入：</p><ul><li>我为什么明明想静，却总静不下来？</li><li>我现在是被什么牵着走？</li><li>我能不能在应物之中，慢慢让心不再那么散乱？</li></ul><h2 id="【解读层】分段解读" tabindex="-1">【解读层】分段解读 <a class="header-anchor" href="#【解读层】分段解读" aria-label="Permalink to &quot;【解读层】分段解读&quot;">​</a></h2><h3 id="_1-道体总说" tabindex="-1">1. 道体总说 <a class="header-anchor" href="#_1-道体总说" aria-label="Permalink to &quot;1. 道体总说&quot;">​</a></h3><p>“大道无形，大道无情，大道无名”并不是说大道空无一物，而是在说：它不以可执取的方式存在，却始终在生育天地、运行日月、长养万物。</p><p>这里的“无”，不是冷，也不是没有，而是不居功、不自显、不可被固定形名所穷尽。</p><h3 id="_2-清浊动静与万物生成" tabindex="-1">2. 清浊动静与万物生成 <a class="header-anchor" href="#_2-清浊动静与万物生成" aria-label="Permalink to &quot;2. 清浊动静与万物生成&quot;">​</a></h3><p>这一段把大道展开成一种宇宙生成秩序：清浊、动静并行流转，万物由此而生。</p><p>其中“清者浊之源，动者静之基”尤其重要。它提醒我们，这些两端不是互相切断的，而是一体流行、互为根柢。</p><p>“人能常清静，天地悉皆归”也不一定是外界忽然安静下来，而更像是说：当人的心回到较清明、较安定的状态时，人与天地万物的关系也重新变得顺一些。</p><h3 id="_3-人心为何不静" tabindex="-1">3. 人心为何不静 <a class="header-anchor" href="#_3-人心为何不静" aria-label="Permalink to &quot;3. 人心为何不静&quot;">​</a></h3><p>“夫人神好清，而心扰之；人心好静，而欲牵之”这几句几乎是全篇的心脉。</p><p>它没有先责备人，而是先承认：人本来就向往清静。问题不在于“人不想静”，而在于心会自扰，欲会牵引。</p><p>所以清静工夫，并不是先怪外界，而是先看见：真正让自己散乱的，常常是心和欲在里面不断翻动。</p><h3 id="_4-观照工夫" tabindex="-1">4. 观照工夫 <a class="header-anchor" href="#_4-观照工夫" aria-label="Permalink to &quot;4. 观照工夫&quot;">​</a></h3><p>“内观其心，心无其心；外观其形，形无其形；远观其物，物无其物”并不是在否定心、身体和世界，而是在松开对它们的执著。</p><p>这里的“无”，不是抹掉对象，而是让它们从“绝对中心”的位置上退下来。看穿，不是否定；放下，不是抹掉。</p><h3 id="_5-真静与得道" tabindex="-1">5. 真静与得道 <a class="header-anchor" href="#_5-真静与得道" aria-label="Permalink to &quot;5. 真静与得道&quot;">​</a></h3><p>“欲既不生，即是真静”容易被误读成必须一下子完全无欲。但从修持经验看，更可理解为：不是欲永远不起，而是欲起时，心不再尽被它牵着走。</p><p>“真常应物，常应常静”是这一段最重要的落点。真正的清静不是躲开万物之后才成立，而是在应物之中仍不失其静。</p><p>“渐入真道”“虽名得道，实无所得”又进一步提醒人：可以说“得道”，但不要把它理解成占有了什么。真正的“得”，反而是越来越不执著于“我得到了什么”。</p><h3 id="_6-传承与护持附录" tabindex="-1">6. 传承与护持附录 <a class="header-anchor" href="#_6-传承与护持附录" aria-label="Permalink to &quot;6. 传承与护持附录&quot;">​</a></h3><p>后面的葛翁、左玄真人、正一真人数段，主要承担的是传承、护持与感应的说明功能。</p><p>它们与正文关于“清静”“遣欲”“观照”“渐入真道”的主线不同，更适合单列为附录来读。前者偏经典权威性与信受传统，后者才是本文哲理与修心方法的主体。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>大道没有固定形状，却孕育天地；大道没有私情偏向，却推动日月运行；大道没有固定名称，却长养万物。</p><p>万物在清与浊、动与静的流转中生成，而人的心本来也向往清静，只是常被心的扰动与欲的牵引带走。若能慢慢遣欲、澄心、观照心形与万物，不再把念头、形相与外物执得太实，人便会逐渐回到一种更澄明安定的状态。</p><p>真正的清静，不是逃离世界，也不是把自己压成死寂，而是在应物之中仍不失其根。这样一路走下去，便是渐入真道；虽名得道，实无所得。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>读这部经时，我最强烈的感受之一，是它没有把“清静”讲成一种脱离现实的小技巧，而是始终把人的心放回到更大的秩序里。</p><p>前面“大道无形，大道无情，大道无名”那几句，我第一次读时，心里其实先掠过一点说不清的悲意。好像它什么都不说，什么都不为自己留下，只有无形、无情、无名。可紧接着又看到“生育天地”“运行日月”“长养万物”，那一点悲意又慢慢散开了。原来它不是冷，也不是远，而是一直都在，一直都做着最根本的事，只是不张扬而已。读到这里时，我反而会生出一点很温厚的感觉，像回到源头，也像回到某种更大的怀抱里。</p><p>比如“人能常清静，天地悉皆归”，我现在更愿意把它理解成：不是环境先安静了，而是心先不再那么容易被外境带走。有一次中午我在一家饺子店吃饭，门口循环播着很吵的广告，照理说那种声音很刺耳。可那天我边吃边读书，读着读着，慢慢看进去了，也跟着内容在想。等我起身离开时，广告其实还在响，但它已经没有那么能伤到我了。环境并没有变清静，是我那一会儿没有被它牵走。现在回头再看这句，就会觉得它说得很实在。</p><p>再比如“人心好静，而欲牵之”，我更有共鸣的不是“心自己乱”，而是“欲把心牵走”。这种“欲”也并不总是什么宏大的东西，很多时候就很具体，很日常。比如突然起来的性欲，或者别的杂念，它来的时候，心会一下子被拽过去。我现在越来越觉得，粗暴压住它没有用，硬要装作没有也没有用。比较适合我的方式，是先看见它，承认它来了；如果它一时不肯走，那就安抚它一会儿，慢慢呼吸，看着它，不急着跟它打架。等它跳够了、闹够了、像是把那股劲表达完了，它反而会自己缓下来。等我再回到手上的事，心也就一点点收回来了。所以我现在理解“遣欲”，不是把欲消灭掉，而是不再被它一路拖着走。</p><p>读到“内观其心，心无其心；外观其形，形无其形；远观其物，物无其物”时，我最先感到的也不是玄，不是空，而是一种“松开”。很多东西原本被我抓得太实，好像非得立刻定义清楚、说明白、抓牢了，心里才踏实。可这几句像是在提醒我：可以去理解，可以去命名，但不要把那个名字、那个解释，当成它全部的本体。人一旦抓得太死，反而离它远了。</p><p>读到“真常应物，常应常静”时，我的感受又更深了一层。因为对现在的我来说，欲并不会一下子不生，所以我不再急着追求某种绝对的“真静”，而更愿意练习在面对万物、面对念头、面对欲望时，去理、去应、去观、去省。静也许不是强求来的，而是在一次次应物之后，慢慢自己显出来的。</p><p>至于“渐入真道”“虽名得道，实无所得”，它也提醒我：人总是需要一点鼓励的，需要知道自己没有白走这段路，所以“渐入真道”这句话会让人心里一暖。可经文马上又补上一句“实无所得”，像是轻轻按住人的肩膀，提醒不要又起了新的执著。我现在很喜欢这种分寸：可以继续走，可以继续学，也可以承认自己有一点点进入了，但心里还是要知道，道不是拿来占有的。若真有一点所得，也最好还是放下“我得了”的心，继续往前。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《太上老君说常清静经》</li><li>道教经典通行系统</li></ul>',49))])}const j=c(b,[["render",x]]);export{y as __pageData,j as default};
